/******************************
 * Validate Law Clerk Comments
 * 
 * by Cinthia Romero
 *****************************/
var validateComments = "YES";
if (this.PE_SAVE_SUBMIT_LC1 == "SAVE" || this.PE_AML_REVIEW_COMPLETE == "Yes") {
    validateComments = "NO";
}
return validateComments;

/****************************
 * Check if Legal user exist
 * 
 * by Cinthia Romero
 ***************************/
var legalUserExist = "NO";
var legalUser = this.PE_RED_FLAG_LEGAL_REVIEW;
if (legalUser != undefined && legalUser != null && legalUser != "") {
    legalUserExist = "YES";
}
return legalUserExist;

/*********************
 * Validate Documents
 * 
 * by Cinthia Romero
 * mofified by Adriana Centellas
 ********************/
/**
 * Document Exist
 *
 * @param string value
 * @return bool
 * 
 * by Cinthia Romero
 */
function documentExist(value) {
    return (value !== null && value !== "" && value !== 0 && value !== [] && (typeof value !== "undefined"));
}

let documentsValidation = {
    SHOW_MESSAGE: "NO",
    MESSAGE: ""
};

//Check if AML Review Complete is Yes to validate documents
if (this.PE_AML_REVIEW_COMPLETE == "Yes") {
    //Check if PE_AML_RESULTS_DOCUMENT has ay least one document
    if (!documentExist(this.PE_AML_RESULTS_DOCUMENT)) {
        documentsValidation.SHOW_MESSAGE = "YES";
        documentsValidation.MESSAGE = "Please upload a valid document";
    }
}

return documentsValidation;

/*********************
 * Set copy html link
